<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  *{margin:0;padding:0;box-sizing:border-box}
  body{background:#0d0d1a;color:#e0e0e0;font-family:'Segoe UI',system-ui,sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;overflow:hidden;user-select:none}
  #container{display:flex;flex-direction:column;align-items:center;gap:16px}
  #sand{border:2px solid #2a2a3e;border-radius:8px;cursor:crosshair;background:#11111a;image-rendering:pixelated;width:min(80vw,500px);height:min(70vh,500px)}
  #controls{display:flex;gap:8px;flex-wrap:wrap;justify-content:center;align-items:center}
  button{padding:10px 20px;border:none;border-radius:6px;font-size:14px;font-weight:700;cursor:pointer;transition:all .15s ease;text-transform:uppercase;letter-spacing:.5px;color:#fff}
  button:hover{transform:translateY(-2px);box-shadow:0 6px 20px rgba(0,0,0,.5)}
  button:active{transform:translateY(0);box-shadow:none}
  #mat-sand{background:linear-gradient(135deg,#e6a832,#c48820)}
  #mat-water{background:linear-gradient(135deg,#3279e6,#2060c4)}
  #mat-wall{background:linear-gradient(135deg,#888,#666)}
  #mat-acid{background:linear-gradient(135deg,#32e65a,#20b848)}
  #mat-empty{background:linear-gradient(135deg,#e63232,#c42020)}
  #clear{background:linear-gradient(135deg,#555,#333);margin-left:8px}
  .active{outline:3px solid #fff;outline-offset:2px;filter:brightness(1.2)}
</style>
</head>
<body>
<div id="container">
  <canvas id="sand"></canvas>
  <div id="controls">
    <button id="mat-sand" class="active">Sand</button>
    <button id="mat-water">Water</button>
    <button id="mat-wall">Wall</button>
    <button id="mat-acid">Acid</button>
    <button id="mat-empty">Eraser</button>
    <button id="clear">Clear All</button>
  </div>
</div>
<script>
(function(){
  const W=100, H=100, CS=5;
  const canvas=document.getElementById('sand');
  const ctx=canvas.getContext('2d');
  canvas.width=W*CS; canvas.height=H*CS;

  let grid=createGrid(), nextGrid=createGrid();
  function createGrid(){return Array.from({length:H},()=>new Array(W).fill('empty'))}

  const COL={empty:[17,17,26],sand:[230,185,50],water:[50,130,240],wall:[130,130,135],acid:[50,240,80]};

  let sel='sand', painting=false;
  const btns={sand:document.getElementById('mat-sand'),water:document.getElementById('mat-water'),wall:document.getElementById('mat-wall'),acid:document.getElementById('mat-acid'),empty:document.getElementById('mat-empty')};

  function selectMat(m){sel=m;Object.values(btns).forEach(b=>b.classList.remove('active'));if(btns[m])btns[m].classList.add('active')}
  for(const[k,b]of Object.entries(btns))b.addEventListener('click',()=>selectMat(k));
  document.getElementById('clear').addEventListener('click',()=>{grid=createGrid();nextGrid=createGrid()});

  function gpos(e){const r=canvas.getBoundingClientRect(),sx=canvas.width/r.width,sy=canvas.height/r.height;return{x:Math.floor((e.clientX-r.left)*sx/CS),y:Math.floor((e.clientY-r.top)*sy/CS)}}
  function paint(gx,gy){if(gx<0||gx>=W||gy<0||gy>=H)return;grid[gy][gx]=sel}

  canvas.addEventListener('mousedown',e=>{painting=true;paint(...Object.values(gpos(e)))});
  canvas.addEventListener('mousemove',e=>{if(!painting)return;paint(...Object.values(gpos(e)))});
  window.addEventListener('mouseup',()=>{painting=false});
  canvas.addEventListener('contextmenu',e=>e.preventDefault());

  function tick(){
    for(let y=0;y<H;y++)for(let x=0;x<W;x++)nextGrid[y][x]=grid[y][x];
    for(let y=H-1;y>=0;y--){
      for(let x=0;x<W;x++){
        const c=grid[y][x];
        if(c==='empty'||c==='wall')continue;
        if(c==='sand')doSand(x,y);
        else if(c==='water')doLiquid(x,y,'water');
        else if(c==='acid')doAcid(x,y);
      }
    }
    [grid,nextGrid]=[nextGrid,grid];
  }

  function doSand(x,y){
    if(y+1<H){
      if(grid[y+1][x]==='empty'){nextGrid[y+1][x]='sand';nextGrid[y][x]='empty';return}
      if(grid[y+1][x]==='water'||grid[y+1][x]==='acid'){const b=grid[y+1][x];nextGrid[y+1][x]='sand';nextGrid[y][x]=b;return}
    }
    let d=Math.random()<.5?-1:1;
    for(let i=0;i<2;i++){
      const nx=x+(i===0?d:-d);
      if(nx>=0&&nx<W&&y+1<H){
        if(grid[y+1][nx]==='empty'){nextGrid[y+1][nx]='sand';nextGrid[y][x]='empty';return}
        if(grid[y+1][nx]==='water'||grid[y+1][nx]==='acid'){const b=grid[y+1][nx];nextGrid[y+1][nx]='sand';nextGrid[y][x]=b;return}
      }
    }
  }

  function doLiquid(x,y,type){
    if(y+1<H){
      if(grid[y+1][x]==='empty'){nextGrid[y+1][x]=type;nextGrid[y][x]='empty';return true}
      if(grid[y+1][x]===type||grid[y+1][x]==='water'||grid[y+1][x]==='acid'){const b=grid[y+1][x];nextGrid[y+1][x]=type;nextGrid[y][x]=b;return true}
    }
    let d=Math.random()<.5?-1:1;
    for(let i=0;i<2;i++){
      const nx=x+(i===0?d:-d);
      if(nx>=0&&nx<W&&y+1<H){
        if(grid[y+1][nx]==='empty'){nextGrid[y+1][nx]=type;nextGrid[y][x]='empty';return true}
        if(grid[y+1][nx]===type||grid[y+1][nx]==='water'||grid[y+1][nx]==='acid'){const b=grid[y+1][nx];nextGrid[y+1][nx]=type;nextGrid[y][x]=b;return true}
      }
    }
    for(let i=0;i<2;i++){
      const nx=x+(i===0?d:-d);
      if(nx>=0&&nx<W&&grid[y][nx]==='empty'){nextGrid[y][nx]=type;nextGrid[y][x]='empty';return true}
    }
    return false;
  }

  function doAcid(x,y){
    const dirs=[[0,1],[-1,0],[1,0]];
    for(const[dx,dy]of dirs){
      const nx=x+dx,ny=y+dy;
      if(nx>=0&&nx<W&&ny>=0&&ny<H&&grid[ny][nx]==='sand'||nx>=0&&nx<W&&ny>=0&&ny<H&&grid[ny][nx]==='wall'){
        nextGrid[y][x]='empty';nextGrid[ny][nx]='empty';return;
      }
    }
    doLiquid(x,y,'acid');
  }

  function render(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    for(let gy=0;gy<H;gy++){
      for(let gx=0;gx<W;gx++){
        const c=grid[gy][gx];if(c==='empty')continue;
        const[col]=COL[c],v=((gx*7+gy*13)&15)-8;
        ctx.fillStyle=`rgb(${Math.min(255,col[0]+v)},${Math.min(255,col[1]+v)},${Math.min(255,col[2]+v)})`;
        ctx.fillRect(gx*CS,gy*CS,CS,CS);
      }
    }
  }

  let last=0;
  function anim(t){requestAnimationFrame(anim);if(t-last>=16){last=t;tick();render()}}
  requestAnimationFrame(anim);

  window.sim={
    get w(){return W},get h(){return H},
    tick(n){for(let i=0;i<n;i++)tick()},
    get(x,y){if(x<0||x>=W||y<0||y>=H)return'empty';return grid[y][x]},
    set(x,y,m){if(x<0||x>=W||y<0||y>=H)return;grid[y][x]=m},
    clear(){grid=createGrid();nextGrid=createGrid()}
  };
})();
</script>
</body>
</html>
